+    cam_info_msg_.binning_y = 0;
+    cam_info_msg_.roi.do_rectify = false;
+    cam_info_msg_.roi.height = 0;
+    cam_info_msg_.roi.width = 0;
+    cam_info_msg_.roi.x_offset = 0;
